async function getMicrosoftToken(){
  const saved=await loadOAuthTokens('microsoft');
  if(!saved)return null;
  const expiresAt=(Number(saved.issued_at)||0)+(Number(saved.expires_in)||3600)*1000-60000;
  if(saved.access_token&&Date.now()<expiresAt)return saved.access_token;
  if(!saved.refresh_token)return saved.access_token||null;
  const r=await fetch('https://login.microsoftonline.com/common/oauth2/v2.0/token',{
    method:'POST',
    headers:{'Content-Type':'application/x-www-form-urlencoded'},
    body:new URLSearchParams({
      client_id:MICROSOFT_CLIENT_ID,
      client_secret:MICROSOFT_CLIENT_SECRET,
      refresh_token:saved.refresh_token,
      grant_type:'refresh_token',
      scope:MICROSOFT_SCOPES.join(' ')
    })
  });
  const fresh=await readJsonResponse(r);
  if(!r.ok||fresh.error){
    console.error('Microsoft token refresh failed:',fresh.error_description||fresh.error||r.status);
    return saved.access_token||null;
  }
  const next={...saved,...fresh,refresh_token:fresh.refresh_token||saved.refresh_token,issued_at:Date.now()};
  await saveOAuthTokens('microsoft',next);
  return next.access_token;
}

async function fetchOutlookCalendarEvents(start,end,maxResults=75){
  const token=await getMicrosoftToken();
  if(!token) throw new Error('Microsoft auth required');
  const filter=`start/dateTime ge '${start.toISOString()}' and start/dateTime le '${end.toISOString()}'`;
  const url='https://graph.microsoft.com/v1.0/me/events?'+new URLSearchParams({
    '$top':String(maxResults),
    '$orderby':'start/dateTime',
    '$select':'id,subject,bodyPreview,start,end,location,attendees,organizer,webLink,isCancelled,onlineMeeting,onlineMeetingUrl',
    '$filter':filter
  }).toString();
  const r=await fetch(url,{headers:{Authorization:`Bearer ${token}`,Prefer:`outlook.timezone="${CLIENT_CONFIG.timezone}"`}});
  const d=await readJsonResponse(r);
  if(!r.ok) throw new Error(d.error?.message||`Microsoft calendar ${r.status}`);
  return (d.value||[]).map(e=>({
    id:e.id,
    summary:e.subject||'(No title)',
    title:e.subject||'(No title)',
    startTime:e.start?.dateTime,
    endTime:e.end?.dateTime,
    location:e.location?.displayName||'',
    description:e.bodyPreview||'',
    attendees:(e.attendees||[]).map(a=>({name:a.emailAddress?.name||'',email:String(a.emailAddress?.address||'').toLowerCase(),responseStatus:a.status?.response||''})),
    organizer:e.organizer?.emailAddress?{name:e.organizer.emailAddress.name||'',email:String(e.organizer.emailAddress.address||'').toLowerCase()}:{},
    status:e.isCancelled?'cancelled':'confirmed',
    source:'outlook',
    calendarName:'Outlook Calendar',
    webLink:e.webLink||'',
    meetingLink:e.onlineMeeting?.joinUrl||e.onlineMeetingUrl||e.webLink||'',
    raw:e
  }));
}

async function fetchGoogleCalendarEvents(start,end,maxResults=50){
  const token = await getGoogleToken();
  if(!token) throw new Error('Google auth required');
  const url = `https://www.googleapis.com/calendar/v3/calendars/primary/events?timeMin=${start.toISOString()}&timeMax=${end.toISOString()}&singleEvents=true&orderBy=startTime&maxResults=${maxResults}`;
  const r = await fetch(url, {headers:{Authorization:`Bearer ${token}`}});
  const d = await r.json();
  if(d.error) throw new Error(d.error.message || 'Google calendar error');
  return (d.items||[]).map(e=>({
    id: e.id,
    summary: e.summary||'(No title)',
    title: e.summary||'(No title)',
    startTime: e.start?.dateTime||e.start?.date,
    endTime: e.end?.dateTime||e.end?.date,
    location: e.location,
    description: e.description,
    attendees: (e.attendees||[]).map(a=>({name:a.displayName||'',email:a.email||'',responseStatus:a.responseStatus||''})),
    organizer:e.organizer?{name:e.organizer.displayName||'',email:e.organizer.email||''}:{},
    status: e.status,
    source: 'google',
    calendarName: 'Google Calendar',
    meetingLink:e.hangoutLink||(e.conferenceData?.entryPoints||[]).find(p=>p.entryPointType==='video')?.uri||'',
    raw:e
  }));
}

function defaultTaskCalendarSettings(){
  return {
    task_calendarization_mode:'suggest',
    default_duration_minutes:Number(process.env.VAL_TASK_BLOCK_MINUTES||45),
    default_reminder_minutes:Number(process.env.VAL_TASK_REMINDER_MINUTES||10),
    default_provider:String(process.env.VAL_TASK_CALENDAR_PROVIDER||'auto').toLowerCase(),
    workday_start_hour:Number(process.env.VAL_WORKDAY_START_HOUR||9),
    workday_end_hour:Number(process.env.VAL_WORKDAY_END_HOUR||17),
    avoid_weekends:String(process.env.VAL_TASK_AVOID_WEEKENDS||'true')!=='false',
    completion_behavior:String(process.env.VAL_TASK_COMPLETION_BEHAVIOR||'keep_event_as_done')
  };
}
function taskBlockTitle(task,prefix='TASK'){
  const raw=String(task?.title||task?.taskTitle||'VAL task').replace(/^(TASK|FOCUS|DONE):\s*/i,'').trim()||'VAL task';
  return `${prefix}: ${raw}`;
}
function doneTaskBlockTitle(task){
  const raw=String(task?.title||task?.taskTitle||'VAL task').replace(/^(TASK|FOCUS|DONE):\s*/i,'').trim()||'VAL task';
  return `DONE: ${raw}`;
}
function taskBlockDescription(task){
  return [
    'Protected work block created by VAL.',
    'No attendees were invited. No meeting link was created.',
    task?.contactName?`Related contact: ${task.contactName}`:'',
    task?.notes?`\nTask notes:\n${String(task.notes).slice(0,1800)}`:''
  ].filter(Boolean).join('\n');
}
function pickTaskProvider(preferred){
  preferred=String(preferred||'auto').toLowerCase();
  if(preferred==='google'||preferred==='outlook') return preferred;
  if(googleTokens?.refresh_token||googleTokens?.access_token) return 'google';
  return 'outlook';
}
function parseTaskDate(value){
  if(!value)return null;
  const d=new Date(value);
  return isNaN(d.getTime())?null:d;
}
function addMinutes(date,minutes){return new Date(date.getTime()+Number(minutes||0)*60000);}
function intervalsOverlap(aStart,aEnd,bStart,bEnd){return aStart<bEnd&&bStart<aEnd;}
async function createGoogleTaskBlock(task,{start,end,calendarId='primary',durationMinutes,focus=false}={}){
  const token=await getGoogleToken();
  if(!token) throw new Error(lastGoogleAuthError||'Google auth required');
  const event={
    summary:taskBlockTitle(task,focus?'FOCUS':'TASK'),
    description:taskBlockDescription(task),
    start:{dateTime:start.toISOString(),timeZone:CLIENT_CONFIG.timezone},
    end:{dateTime:end.toISOString(),timeZone:CLIENT_CONFIG.timezone},
    transparency:'opaque',
    visibility:'private',
    attendees:[],
    reminders:{useDefault:false,overrides:[{method:'popup',minutes:Number(defaultTaskCalendarSettings().default_reminder_minutes||10)}]},
    extendedProperties:{private:{val_task_id:task.id,val_block_type:'task',estimated_duration_minutes:String(durationMinutes||'')}}
  };
  const url=`https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(calendarId)}/events?sendUpdates=none`;
  const r=await fetch(url,{method:'POST',headers:{Authorization:`Bearer ${token}`,'Content-Type':'application/json'},body:JSON.stringify(event)});
  const d=await readJsonResponse(r);
  if(!r.ok||d.error) throw new Error(d.error?.message||`Google task block failed (${r.status})`);
  return {provider:'google',calendarId,eventId:d.id,webLink:d.htmlLink||'',raw:d};
}
