// GMAIL — replies from GHL contacts only
// ════════════════════════════════════════════════════════

app.get('/api/google/gmail', async (req, res) => {
  try {
    const token = await getGoogleToken();
    if(!token) return res.json({emails:[], needsAuth: true});

    // First get GHL contacts to cross-reference
    const contactsData = await ghl('GET', `/contacts/?locationId=${GHL_LOC}&limit=100&sortBy=date_added&sortDirection=desc`);
    const contacts = contactsData.contacts||[];
    const contactEmails = new Set(contacts.map(c=>c.email).filter(Boolean).map(e=>e.toLowerCase()));

    // Search Gmail for recent unread messages
    const searchUrl = `https://www.googleapis.com/gmail/v1/users/me/messages?q=is:unread newer_than:7d&maxResults=20`;
    const r = await fetch(searchUrl, {headers:{Authorization:`Bearer ${token}`}});
    const d = await r.json();
    const messages = d.messages||[];

    // Fetch each message header
    const emailDetails = await Promise.all(messages.slice(0,10).map(async m=>{
      const mr = await fetch(`https://www.googleapis.com/gmail/v1/users/me/messages/${m.id}?format=metadata&metadataHeaders=From&metadataHeaders=Subject&metadataHeaders=Date`,
        {headers:{Authorization:`Bearer ${token}`}});
      const md = await mr.json();
      const headers = md.payload?.headers||[];
      const from = headers.find(h=>h.name==='From')?.value||'';
      const subject = headers.find(h=>h.name==='Subject')?.value||'';
      const date = headers.find(h=>h.name==='Date')?.value||'';
      const emailMatch = from.match(/<(.+?)>/)||[null,from];
      const fromEmail = emailMatch[1]?.toLowerCase()||'';
      const fromName = from.replace(/<.*>/,'').trim().replace(/"/g,'');
      const isGHLContact = contactEmails.has(fromEmail);
      return {id:m.id, from, fromEmail, fromName, subject, date, isGHLContact};
    }));

    const ghlEmails = emailDetails.filter(e=>e.isGHLContact);
    res.json({emails: emailDetails, ghlEmails, total: messages.length});
  } catch(e) {
    res.json({emails:[], error: e.message});
  }
});

function parseEmailAddress(raw){
  const text=String(raw||'').trim();
  const match=text.match(/^(.*?)\s*<([^>]+)>$/);
  const email=(match?match[2]:text).replace(/"/g,'').trim().toLowerCase();
  const name=(match?match[1]:text.replace(email,'')).replace(/"/g,'').trim();
  return {name:name||email.split('@')[0]||'',email};
}
function decodeBase64Url(value){
  if(!value)return '';
  try{return Buffer.from(String(value).replace(/-/g,'+').replace(/_/g,'/'),'base64').toString('utf8');}
  catch(e){return '';}
}
function extractGmailBody(payload){
  if(!payload)return '';
  if(payload.body?.data)return decodeBase64Url(payload.body.data);
  const parts=payload.parts||[];
  const plain=parts.find(p=>p.mimeType==='text/plain')||parts.find(p=>p.body?.data);
  if(plain?.body?.data)return decodeBase64Url(plain.body.data);
  for(const part of parts){
    const nested=extractGmailBody(part);
    if(nested)return nested;
  }
  return '';
}
function normalizeGmailMessage(md){
  const headers=md.payload?.headers||[];
  const header=name=>headers.find(h=>String(h.name||'').toLowerCase()===name.toLowerCase())?.value||'';
  const from=parseEmailAddress(header('From'));
  const bodyText=extractGmailBody(md.payload)||md.snippet||'';
  const to=String(header('To')||'').split(',').map(parseEmailAddress).filter(v=>v.email);
  const cc=String(header('Cc')||'').split(',').map(parseEmailAddress).filter(v=>v.email);
  const attachments=JSON.stringify(md.payload||{}).includes('"filename"');
  const parsedDate=header('Date') ? new Date(header('Date')) : null;
  const internalDate=md.internalDate ? new Date(Number(md.internalDate)) : null;
  const date=parsedDate&&!isNaN(parsedDate.getTime()) ? parsedDate.toISOString() : (internalDate&&!isNaN(internalDate.getTime()) ? internalDate.toISOString() : '');
  return {
    provider:'gmail',
    messageId:md.id||'',
    threadId:md.threadId||'',
    subject:header('Subject')||'(No subject)',
    from,
    to,
    cc,
    date,
    receivedAt:date,
    snippet:md.snippet||'',
    bodyPreview:String(bodyText||'').slice(0,700),
    bodyText:String(bodyText||''),
    labels:md.labelIds||[],
    hasAttachments:attachments,
    webLink:`https://mail.google.com/mail/u/0/#inbox/${md.threadId||md.id}`,
    classification:'',
    recommendedAction:'',
    matchedContact:{},
    matchedRuleId:'',
    requiresApproval:true,
    confidence:'medium'
  };
}
function gmailDateValue(email){
  const value=new Date(email?.date||email?.receivedAt||0).getTime();
  return Number.isFinite(value)?value:0;
}
function sortEmailsNewestFirst(emails=[]){
  return emails.slice().sort((a,b)=>gmailDateValue(b)-gmailDateValue(a));
}
function classifyEmail(email,rules=[]){
  const text=[email.subject,email.snippet,email.bodyPreview,email.bodyText,email.from?.email].join(' ').toLowerCase();
  const domain=(email.from?.email||'').split('@')[1]||'';
  const activeRules=rules.filter(r=>r.is_active!==false&&r.isActive!==false);
  for(const rule of activeRules){
    const conditions=rule.conditions||rule.conditions_json||rule.conditionsJson||{};
    const fromEmail=String(email.from?.email||'').toLowerCase();
    const fromDomain=domain.toLowerCase();
    const needle=String(conditions.text_contains||conditions.body_contains||conditions.subject_contains||conditions.keyword||'').toLowerCase();
    const matchesSender=conditions.from_email&&String(conditions.from_email).toLowerCase()===fromEmail;
    const matchesDomain=conditions.from_domain&&String(conditions.from_domain).toLowerCase()===fromDomain;
    const matchesText=needle&&text.includes(needle);
    if(matchesSender || matchesDomain || matchesText){
      const type=rule.ruleType||rule.rule_type;
      const actions=rule.actions||rule.actions_json||rule.actionsJson||{};
      const actionLabel=String(actions.action||actions.label||'').toLowerCase();
      const lowPriority=type==='ignore_sender'||type==='ignore_domain'||actionLabel==='low_priority'||actionLabel==='not_important';
      const draftReply=type==='draft_reply'||actionLabel==='draft_reply';
      return {
        classification:lowPriority?'ignored':type==='forward_sender'||type==='forward_category'?'forward_to_team':draftReply?'needs_reply':type==='vip_priority'?'needs_attention':'needs_attention',
        reason:`Matched saved rule: ${rule.rule_name||rule.ruleName||type}`,
        recommendedAction:actions.action==='forward'?`Forward to ${actions.forward_to}`:(lowPriority?'Keep out of Needs My Attention':actions.action||type),
        confidence:'high',
        matchedRuleId:rule.id,
        requiresApproval:(rule.approvalMode||rule.approval_mode)!=='always_auto'
      };
    }
  }
  if(/\b(unsubscribe|special offer|limited time|book a call|seo|cold email|quick question|sponsor|advertis|newsletter)\b/.test(text)){
    return {classification:'solicitation',reason:'Looks promotional or unsolicited.',recommendedAction:'Move to low priority review.',confidence:'medium',requiresApproval:true};
  }
  if(/\b(invoice|contract|agreement|legal|payment|billing|complaint|confidential|medical|hr|termination|benefits|security|deadline|approval|approve|urgent|escalat)\b/.test(text)){
    return {classification:'needs_attention',reason:'Sensitive or high-stakes language detected.',recommendedAction:'Review before any action.',confidence:'high',requiresApproval:true,sensitive:true};
  }
  if(/\b(intro|introduction|referral|connect you|introduce you|introduced|warm intro|warm introduction)\b/.test(text)){
    return {classification:'needs_reply',reason:'Warm introduction opportunity asks for reply language.',recommendedAction:'Draft the intro response for approval.',confidence:'high',requiresApproval:true};
  }
  if(/\b(can you|could you|please|confirm|question|let me know|reply|respond|available|schedule|meeting|estimate|quote|photos|photo|review|feedback|timeline|next thursday|by friday|client|customer)\b/.test(text)){
    return {classification:'needs_reply',reason:'Asks for a response or decision.',recommendedAction:'Draft a reply for approval.',confidence:'high',requiresApproval:true};
  }
  if(/\b(proposal|pricing|contract|intro|introduction|following up|checking in|demo|next step|open loop|waiting|decision|opportunity|partnership)\b/.test(text)){
    return {classification:'waiting_on_response',reason:'Looks connected to a deal, intro, or follow-up loop.',recommendedAction:'Track response and draft follow-up if needed.',confidence:'medium',requiresApproval:true};
  }
  return {classification:'low_priority',reason:'No urgent request detected.',recommendedAction:'Keep in low priority unless this sender matters.',confidence:'medium',requiresApproval:true};
}
function emailShouldPrepareDraft(email){
  const text=[email.subject,email.snippet,email.bodyPreview,email.bodyText,email.recommendedAction,email.reason].join(' ');
  if(['needs_reply','appointment_recap_needed'].includes(email.classification))return true;
  if(/\bdraft\b/i.test(email.recommendedAction||''))return true;
  return /\b(intro|introduction|referral|connect you|warm intro|send me|tight version|one paragraph|reply|respond|let me know)\b/i.test(text)&&!['ignored','low_priority','solicitation','spam_like'].includes(email.classification);
}
function emailDraftStableId(email){
  const raw=[tenantId(),currentUserId(),email.provider||'email',email.messageId||email.threadId||email.subject||'unknown'].join(':');
  return 'draft_email_'+crypto.createHash('sha1').update(raw).digest('hex').slice(0,24);
}
function buildEmailReplyDraft(email){
  const subject=`Re: ${email.subject||''}`.trim();
  const name=(email.from?.name||'').split(/\s+/)[0]||'';
  const text=[email.subject,email.snippet,email.bodyPreview,email.bodyText,email.reason,email.recommendedAction].join(' ');
  const intro=/\b(intro|introduction|referral|connect you|warm intro|warm introduction|tight version|one paragraph)\b/i.test(text);
  if(intro){
    return {
      subject,
      body:[
        `Hi ${name},`.replace(/\s+,/,','),
        '',
        'Thank you. I really appreciate the introduction.',
        '',
        'Here is a tight version you can use:',
        '',
        'VAL helps leaders stay on top of the relationships, meetings, decisions, and follow-through that actually move the business. It turns communication into clear next actions, drafts, and memory so important people and promises do not fall through the cracks.',
        '',
        'Grateful for you making the connection.',
        '',
        'Best,'
      ].join('\n')
    };
  }
  return {
    subject,
    body:[
      `Hi ${name},`.replace(/\s+,/,','),
      '',
      'Thank you for your note. I wanted to respond thoughtfully.',
      '',
      email.reason?`I saw this needs attention because ${email.reason.charAt(0).toLowerCase()+email.reason.slice(1)}`:'I saw this needs a clear reply.',
      '',
      'Here is what I recommend as the next step:',
      '',
      email.recommendedAction||'Let me take a closer look and follow up with the right next step.',
      '',
      'Best,'
    ].join('\n')
  };
}
async function prepareEmailDraftIfNeeded(email){
  if(!emailShouldPrepareDraft(email))return null;
  const draft=buildEmailReplyDraft(email);
  return saveInternalDraft({
    id:emailDraftStableId(email),
    draftType:'email_reply',
    provider:'internal',
    subject:draft.subject,
    body:draft.body,
    status:'draft',
    sourceContext:{
      source:'executive_inbox_auto_draft',
      provider:email.provider||'email',
      messageId:email.messageId||'',
      threadId:email.threadId||'',
      to:email.from?.email||'',
      senderName:email.from?.name||'',
      why:email.reason||'',
      recommendedAction:email.recommendedAction||'',
      classification:email.classification||''
    }
  });
}
function emailEvidenceStatus(email){
  const classification=String(email.classification||'').toLowerCase();
  if(['ignored','low_priority','solicitation','spam_like'].includes(classification))return 'ignored';
  if(['needs_attention','needs_reply','waiting_on_response','forward_to_team','appointment_recap_needed'].includes(classification))return 'action_suggested';
  return 'parsed';
}
function emailConfidenceNumber(confidence){
  const c=String(confidence||'medium').toLowerCase();
  if(c==='high')return 0.9;
  if(c==='low')return 0.45;
  return 0.65;
}
function emailParticipantsJson(email){
  return [
    email.from?{role:'from',name:email.from.name||'',email:email.from.email||''}:null,
    ...(email.to||[]).map(p=>({role:'to',name:p.name||'',email:p.email||''})),
    ...(email.cc||[]).map(p=>({role:'cc',name:p.name||'',email:p.email||''}))
  ].filter(p=>p&&(p.name||p.email));
}
function emailSourceText(email){
  return [email.subject,email.bodyText,email.bodyPreview,email.snippet].filter(Boolean).join('\n\n').trim();
}
function emailObservationCandidates(email){
  const text=emailSourceText(email), lower=text.toLowerCase(), candidates=[];
  const add=(observationType,content,exactQuote='',confidence=emailConfidenceNumber(email.confidence),status='observed')=>{
    if(content)candidates.push({observationType,content,exactQuote:exactQuote||transcriptSupportingQuote(text,content),confidence,status});
  };
  if(/\b(unsubscribe|newsletter|digest|roundup)\b/i.test(lower))add('newsletter','Email appears to be a newsletter or bulk update.',email.snippet||email.subject,0.85,'ignored');
  if(/\b(receipt|order confirmation|payment received|invoice paid|your order|transaction)\b/i.test(lower))add('receipt','Email appears to be a receipt or transactional record.',email.snippet||email.subject,0.85,'ignored');
  if(/\b(seo|special offer|limited time|cold email|sponsor|advertis|book a call|unsubscribe)\b/i.test(lower))add('spam','Email appears promotional, unsolicited, or low relationship value.',email.snippet||email.subject,0.75,'ignored');
  if(email.classification==='needs_reply')add('reply_needed',email.reason||'Email asks for a response or decision.',email.snippet||email.bodyPreview,emailConfidenceNumber(email.confidence),'needs_review');
  if(email.classification==='waiting_on_response')add('follow_up',email.reason||'Thread appears to be waiting on a response.',email.snippet||email.bodyPreview,emailConfidenceNumber(email.confidence),'action_suggested');
  if(/\b(price|pricing|cost|quote|estimate|budget|how much|starting at|proposal)\b/i.test(lower))add('pricing_question','Email includes pricing, cost, quote, estimate, budget, or proposal language.',email.snippet||email.bodyPreview,0.8,'needs_review');
  if(/\b(available|availability|schedule|meeting|meet|call|zoom|google meet|calendar)\b/i.test(lower))add('meeting_request','Email includes scheduling or meeting language.',email.snippet||email.bodyPreview,0.75,'needs_review');
  if(/\b(send|share|attach|attachment|document|proposal|contract|agreement|worksheet|file|pdf|doc)\b/i.test(lower))add('document_request','Email may involve a document request or document follow-up.',email.snippet||email.bodyPreview,0.7,'needs_review');
  if(/\b(intro|introduction|referral|partner|partnership|client|lead|opportunity|proposal)\b/i.test(lower))add('opportunity','Email may contain relationship or revenue opportunity signal.',email.snippet||email.bodyPreview,0.75,'needs_review');
  if(/\b(urgent|concern|issue|blocked|problem|risk|complaint|confused|not sure|worried)\b/i.test(lower))add('risk','Email may contain a risk, blocker, or relationship concern.',email.snippet||email.bodyPreview,0.75,'needs_review');
  if(/\b(thank you|appreciate|excited|looking forward|great talking|good to meet|warm|referred)\b/i.test(lower))add('relationship_signal','Email contains relationship momentum or warmth.',email.snippet||email.bodyPreview,0.65,'observed');
  if(!candidates.length&&email.classification&&!['low_priority','ignored','solicitation','spam_like'].includes(email.classification))add('relationship_signal',email.reason||'Email may be relationship-relevant.',email.snippet||email.bodyPreview,0.55,'observed');
  return candidates;
}
async function saveEmailEvidence(email){
  if(!email?.messageId)return null;
  const sourceType=email.provider==='outlook'?'outlook_email':'gmail_email';
  const status=emailEvidenceStatus(email);
  const evidence=await saveEvidenceItem({sourceType,sourceId:email.messageId,sourceUrl:email.webLink||'',occurredAt:email.date||email.receivedAt||'',capturedAt:new Date().toISOString(),title:email.subject||'(No subject)',rawText:emailSourceText(email),summary:email.reason||email.snippet||email.bodyPreview||'',participantsJson:emailParticipantsJson(email),entitiesJson:{threadId:email.threadId||'',provider:email.provider||'',classification:email.classification||'',recommendedAction:email.recommendedAction||'',from:email.from||{},hasAttachments:!!email.hasAttachments},confidence:emailConfidenceNumber(email.confidence),status,metadataJson:{provider:email.provider||'',messageId:email.messageId||'',threadId:email.threadId||'',labels:email.labels||[],requiresApproval:!!email.requiresApproval,matchedRuleId:email.matchedRuleId||''}}).catch(()=>null);
  if(!evidence?.id)return null;
  await runObservationEngine(evidence,{candidates:emailObservationCandidates(email),replace:true}).catch(()=>null);
  return evidence;
}
async function saveEmailEvidenceBatch(emails=[]){
  return Promise.all((emails||[]).map(email=>saveEmailEvidence(email))).catch(()=>[]);
}
function emailNeedsResponseSignal(email){
  return /\b(proposal|contract|pricing|introduction|intro|please confirm|let me know|waiting on|can you review|next steps|following up|recap|circle back|review this|thoughts|approve|approval)\b/i.test([email.subject,email.snippet,email.bodyPreview,email.bodyText].join(' '));
}
function businessDaysSince(value){
  const start=new Date(value||0);
  if(isNaN(start.getTime())) return 0;
  let days=0;
  const cur=new Date(start);
  cur.setHours(0,0,0,0);
  const today=new Date();
  today.setHours(0,0,0,0);
  while(cur<today){
    cur.setDate(cur.getDate()+1);
    const day=cur.getDay();
    if(day!==0&&day!==6) days++;
  }
  return days;
}
function waitingOnResponseFromSent(sentEmails=[],allEmails=[],threshold=3){
  const seenThreads=new Set();
  const inboundThreads=new Set(allEmails.filter(e=>!String(e.labels||[]).includes('SENT')).map(e=>e.threadId).filter(Boolean));
  return sentEmails.filter(email=>{
    if(!email.threadId||seenThreads.has(email.threadId)) return false;
    seenThreads.add(email.threadId);
    if(inboundThreads.has(email.threadId)) return false;
    return emailNeedsResponseSignal(email)&&businessDaysSince(email.date||email.receivedAt)>=threshold;
  }).map(email=>({
    ...email,
    classification:'waiting_on_response',
    reason:'Sent email appears to need a response and no later reply was found in the fetched window.',
    recommendedAction:'Draft a concise follow-up or create a follow-up task.',
    confidence:businessDaysSince(email.date||email.receivedAt)>=5?'high':'medium',
    requiresApproval:true
  }));
}
function gmailMeetingContextShape(email,reason='Matched meeting attendee or keyword'){
  return {
    subject:email.subject||'',
    from:email.from?.email||email.from?.name||'',
    date:email.date||email.receivedAt||'',
    summary:email.bodyPreview||email.snippet||'',
    relevanceReason:reason
  };
}
